import{_ as a}from"./chunks/k8s-grafana-template-21410-nodes-wide-annotated.DQAaQJi1.js";import{_ as e}from"./chunks/k8s-grafana-template-21410-node-resources-wide-annotated.CMQjGfrj.js";import{_ as t,c as n,o as p,aN as d}from"./chunks/framework.CqA5BTDU.js";const o="/kb/assets/k8s-prometheus-targets-node-exporter-annotated.DPPIf7AQ.png",i="/kb/assets/k8s-prometheus-targets-kubelet-annotated.BYAsHs_3.png",l="/kb/assets/k8s-prometheus-query-container-cpu-node-annotated.B1YOLoXA.png",v=JSON.parse('{"title":"节点组件监控","description":"","frontmatter":{},"headers":[],"relativePath":"12.可观测性与监控告警/16-节点组件监控.md","filePath":"12.可观测性与监控告警/16-节点组件监控.md","lastUpdated":null}'),r={name:"12.可观测性与监控告警/16-节点组件监控.md"};function c(h,s,k,u,b,m){return p(),n("div",null,[...s[0]||(s[0]=[d('<h1 id="节点组件监控" tabindex="-1">节点组件监控 <a class="header-anchor" href="#节点组件监控" aria-label="Permalink to &quot;节点组件监控&quot;">​</a></h1><p>K8s 节点监控包含两层：Linux 主机本身，以及节点上的 Kubernetes 组件。主机 CPU、内存、磁盘、网络来自 node-exporter；kubelet、探针、volume 和容器资源来自 kubelet/cAdvisor；节点 Ready、DiskPressure、Pod 数量这类对象状态来自 kube-state-metrics。</p><p>节点看起来 CPU、内存正常，Pod 仍然可能因为镜像拉取、探针失败、磁盘压力、CNI 或挂载异常变得不稳定。节点监控要把主机资源、kubelet 状态、容器资源和对象状态放在一起看。</p><h2 id="一、prometheus-target" tabindex="-1">一、Prometheus Target <a class="header-anchor" href="#一、prometheus-target" aria-label="Permalink to &quot;一、Prometheus Target&quot;">​</a></h2><p>操作路径：</p><p><code>Status -&gt; Target health</code> （中文：状态 -&gt; 目标健康）</p><p>节点相关 target 主要有三类：</p><table tabindex="0"><thead><tr><th>scrape pool</th><th>指标来源</th></tr></thead><tbody><tr><td><code>kps-prometheus-node-exporter</code></td><td>Linux 主机资源</td></tr><tr><td><code>kps-kubelet/0</code></td><td>kubelet <code>/metrics</code></td></tr><tr><td><code>kps-kubelet/1</code></td><td>kubelet <code>/metrics/cadvisor</code>，容器资源</td></tr><tr><td><code>kps-kubelet/2</code></td><td>kubelet <code>/metrics/probes</code>，探针指标</td></tr></tbody></table><p>node-exporter 三台节点都为 <code>UP</code>：</p><p><img src="'+o+'" alt="Prometheus node-exporter target"></p><p>kubelet target 包含 <code>/metrics</code> 和 <code>/metrics/cadvisor</code>：</p><p><img src="'+i+`" alt="Prometheus kubelet target"></p><p>Target <code>DOWN</code> 时，展开对应行看 <code>Last error</code>。kubelet 指标通常走 HTTPS，错误可能来自证书、bearer token、ServiceMonitor 或 kubelet 端口访问。</p><h2 id="二、node-exporter" tabindex="-1">二、node-exporter <a class="header-anchor" href="#二、node-exporter" aria-label="Permalink to &quot;二、node-exporter&quot;">​</a></h2><p>node-exporter 采集主机层指标。K8s 里它通常以 DaemonSet 运行，每台节点一个 Pod。</p><p>验证节点数量：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>count(node_uname_info)</span></span></code></pre></div><p>当前结果为 <code>3</code>，说明三台节点都有 node-exporter 数据。</p><p>常用主机指标：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># CPU 使用率，按 instance 区分节点</span></span>
<span class="line"><span>1 - avg by (instance) (</span></span>
<span class="line"><span>  rate(node_cpu_seconds_total{mode=&quot;idle&quot;}[5m])</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 内存可用比例，MemAvailable 比 free 更接近真实可用内存</span></span>
<span class="line"><span>node_memory_MemAvailable_bytes</span></span>
<span class="line"><span>/</span></span>
<span class="line"><span>node_memory_MemTotal_bytes</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 根分区可用比例，排除 tmpfs 和 overlay</span></span>
<span class="line"><span>node_filesystem_avail_bytes{mountpoint=&quot;/&quot;, fstype!~&quot;tmpfs|overlay&quot;}</span></span>
<span class="line"><span>/</span></span>
<span class="line"><span>node_filesystem_size_bytes{mountpoint=&quot;/&quot;, fstype!~&quot;tmpfs|overlay&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 网络接收速率，排除 lo 回环网卡</span></span>
<span class="line"><span>rate(node_network_receive_bytes_total{device!~&quot;lo&quot;}[5m])</span></span></code></pre></div><p>K3s 节点磁盘要关注这些目录：</p><table tabindex="0"><thead><tr><th>路径</th><th>内容</th></tr></thead><tbody><tr><td><code>/var/lib/rancher/k3s</code></td><td>K3s 数据、镜像、数据库或运行时数据</td></tr><tr><td><code>/var/lib/kubelet</code></td><td>kubelet 管理的 Pod、volume 信息</td></tr><tr><td><code>/var/lib/rancher/k3s/agent/containerd</code></td><td>containerd 镜像和容器层</td></tr><tr><td>local-path PV 目录</td><td>K3s local-path provisioner 创建的本地卷</td></tr></tbody></table><p>磁盘空间不足时，Node 可能出现 <code>DiskPressure=True</code>，Pod 可能被驱逐，镜像拉取和容器创建也会失败。</p><h2 id="三、kubelet-和-cadvisor" tabindex="-1">三、kubelet 和 cAdvisor <a class="header-anchor" href="#三、kubelet-和-cadvisor" aria-label="Permalink to &quot;三、kubelet 和 cAdvisor&quot;">​</a></h2><p>kubelet 是每台节点上的 Kubernetes 代理，负责拉起 Pod、执行探针、上报节点状态、管理容器生命周期。cAdvisor 指标由 kubelet 暴露，提供容器级 CPU、内存、网络和文件系统数据。</p><p>kubelet 常见 metrics path：</p><table tabindex="0"><thead><tr><th>metrics path</th><th>说明</th></tr></thead><tbody><tr><td><code>/metrics</code></td><td>kubelet 自身指标</td></tr><tr><td><code>/metrics/cadvisor</code></td><td>容器资源指标</td></tr><tr><td><code>/metrics/probes</code></td><td>探针执行指标</td></tr></tbody></table><p>容器 CPU 查询：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sum by (node) (</span></span>
<span class="line"><span>  rate(container_cpu_usage_seconds_total{container!=&quot;&quot;}[5m])</span></span>
<span class="line"><span>)</span></span></code></pre></div><p><img src="`+l+`" alt="Prometheus 查询容器 CPU"></p><p>常用容器资源查询：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Pod CPU 使用量，适合定位哪个 Pod 消耗 CPU</span></span>
<span class="line"><span>sum by (namespace, pod) (</span></span>
<span class="line"><span>  rate(container_cpu_usage_seconds_total{container!=&quot;&quot;, image!=&quot;&quot;}[5m])</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Pod 内存工作集，接近实际活跃内存</span></span>
<span class="line"><span>sum by (namespace, pod) (</span></span>
<span class="line"><span>  container_memory_working_set_bytes{container!=&quot;&quot;, image!=&quot;&quot;}</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Pod 网络接收</span></span>
<span class="line"><span>sum by (namespace, pod) (</span></span>
<span class="line"><span>  rate(container_network_receive_bytes_total[5m])</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Pod 网络发送</span></span>
<span class="line"><span>sum by (namespace, pod) (</span></span>
<span class="line"><span>  rate(container_network_transmit_bytes_total[5m])</span></span>
<span class="line"><span>)</span></span></code></pre></div><p>CPU 和内存要和 requests/limits 一起看。实际使用量高说明正在消耗资源；requests/limits 接近节点容量，说明调度和限制层面已经紧张。</p><h2 id="四、grafana-节点视图" tabindex="-1">四、Grafana 节点视图 <a class="header-anchor" href="#四、grafana-节点视图" aria-label="Permalink to &quot;四、Grafana 节点视图&quot;">​</a></h2><p>Grafana 的节点视图适合从结果上看三件事：节点是否健康、资源请求是否集中、CPU/内存曲线是否异常。</p><p>节点健康和资源请求：</p><p><img src="`+a+'" alt="Kubernetes 节点健康与资源统计"></p><p>节点 CPU 和内存趋势：</p><p><img src="'+e+`" alt="Kubernetes 节点 CPU 和内存曲线"></p><p>Grafana 面板只是入口。看到某个节点 CPU 或内存异常后，还要回到 Prometheus 或 <code>kubectl top pod</code> 找具体 Pod。</p><h2 id="五、当前资源状态" tabindex="-1">五、当前资源状态 <a class="header-anchor" href="#五、当前资源状态" aria-label="Permalink to &quot;五、当前资源状态&quot;">​</a></h2><p>当前三台节点的资源使用：</p><table tabindex="0"><thead><tr><th>节点</th><th>CPU</th><th>内存</th></tr></thead><tbody><tr><td><code>k3s-agent01</code></td><td><code>50m</code> / <code>1%</code></td><td><code>1263Mi</code> / <code>50%</code></td></tr><tr><td><code>k3s-agent02</code></td><td><code>41m</code> / <code>1%</code></td><td><code>998Mi</code> / <code>50%</code></td></tr><tr><td><code>k3s-server01</code></td><td><code>103m</code> / <code>2%</code></td><td><code>1573Mi</code> / <code>43%</code></td></tr></tbody></table><p>监控组件分布：</p><table tabindex="0"><thead><tr><th>Pod</th><th>节点</th><th>内存</th></tr></thead><tbody><tr><td><code>prometheus-kps-prometheus-0</code></td><td><code>k3s-server01</code></td><td>约 <code>326Mi</code></td></tr><tr><td><code>kps-grafana</code></td><td><code>k3s-agent01</code></td><td>约 <code>263Mi</code></td></tr><tr><td><code>alertmanager-kps-alertmanager-0</code></td><td><code>k3s-server01</code></td><td>约 <code>54Mi</code>，含 config-reloader</td></tr><tr><td><code>kps-kube-state-metrics</code></td><td><code>k3s-server01</code></td><td>约 <code>68Mi</code></td></tr><tr><td><code>kps-operator</code></td><td><code>k3s-server01</code></td><td>约 <code>70Mi</code></td></tr><tr><td><code>node-exporter</code></td><td>三台节点</td><td>每节点约 <code>27-29Mi</code></td></tr></tbody></table><p>这组资源说明轻量 values 生效。Grafana 默认 dashboard sidecar、更多规则和长保留时间都会增加内存占用，小内存测试机上很容易把节点压满。</p><h2 id="六、节点异常排查" tabindex="-1">六、节点异常排查 <a class="header-anchor" href="#六、节点异常排查" aria-label="Permalink to &quot;六、节点异常排查&quot;">​</a></h2><p>节点异常时，先确认 Node Condition，再看节点上有哪些 Pod，最后回到指标看趋势。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看节点状态、版本和节点 IP</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wide</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看 Node Condition、污点、事件和资源分配</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> k3s-agent01</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看某台节点上运行的 Pod</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wide</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --field-selector</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> spec.nodeName=k3s-agent01</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看节点资源使用</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> top</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看内存最高的 Pod</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> top</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --sort-by=memory</span></span></code></pre></div><p>PromQL 侧的常用入口：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Node condition</span></span>
<span class="line"><span>kube_node_status_condition</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 最近 15 分钟容器重启</span></span>
<span class="line"><span>increase(kube_pod_container_status_restarts_total[15m])</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Pod waiting reason</span></span>
<span class="line"><span>kube_pod_container_status_waiting_reason</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 节点文件系统可用比例</span></span>
<span class="line"><span>node_filesystem_avail_bytes{mountpoint=&quot;/&quot;, fstype!~&quot;tmpfs|overlay&quot;}</span></span>
<span class="line"><span>/</span></span>
<span class="line"><span>node_filesystem_size_bytes{mountpoint=&quot;/&quot;, fstype!~&quot;tmpfs|overlay&quot;}</span></span></code></pre></div><p>常见现象和入口：</p><table tabindex="0"><thead><tr><th>现象</th><th>入口</th></tr></thead><tbody><tr><td><code>NotReady</code></td><td><code>kubectl describe node</code>、kubelet 日志、节点网络</td></tr><tr><td><code>DiskPressure</code></td><td>node-exporter 文件系统指标、镜像目录、日志目录、local-path PV</td></tr><tr><td><code>MemoryPressure</code></td><td>节点内存曲线、Pod 内存、OOM 事件</td></tr><tr><td>Pod 大量重启</td><td><code>increase(kube_pod_container_status_restarts_total[15m])</code>、容器日志</td></tr><tr><td>Pod 长期 Pending</td><td>Events、节点资源、污点、节点选择器、PVC</td></tr></tbody></table><p>节点问题很少只靠一条 CPU 曲线定位。Node Condition、kubelet target、cAdvisor 容器指标、Events 和日志要一起看。</p>`,54)])])}const C=t(r,[["render",c]]);export{v as __pageData,C as default};
